  1	import React, { FC, useState } from 'react';
  2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
  3	
  4	import { IoK8sApiRbacV1ClusterRoleBinding } from '@kubevirt-ui/kubevirt-api/kubernetes';
  5	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
  6	import { documentationURL } from '@kubevirt-utils/constants/documentation';
  7	import { ALL_NAMESPACES_SESSION_KEY } from '@kubevirt-utils/hooks/constants';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Button,
 12	  ButtonVariant,
 13	  EmptyState,
 14	  EmptyStateActions,
 15	  EmptyStateBody,
 16	  EmptyStateFooter,
 17	  EmptyStateHeader,
 18	  EmptyStateIcon,
 19	  EmptyStateVariant,
 20	} from '@patternfly/react-core';
 21	import { StorageDomainIcon } from '@patternfly/react-icons';
 22	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
 23	
 24	import { installOrRemoveCheckupsStoragePermissions } from '../utils/utils';
 25	
 26	import './CheckupsStorageListEmptyState.scss';
 27	
 28	type CheckupsStorageListEmptyStateProps = {
 29	  clusterRoleBinding: IoK8sApiRbacV1ClusterRoleBinding;
 30	  isPermitted: boolean;
 31	  isPermittedToInstall: boolean;
 32	  loadingPermissions: boolean;
 33	};
 34	
 35	const CheckupsStorageListEmptyState: FC<CheckupsStorageListEmptyStateProps> = ({
 36	  clusterRoleBinding,
 37	  isPermitted,
 38	  isPermittedToInstall,
 39	  loadingPermissions,
 40	}) => {
 41	  const { t } = useKubevirtTranslation();
 42	  const navigate = useNavigate();
 43	  const location = useLocation();
 44	  const [namespace] = useActiveNamespace();
 45	  const [isLoading, setIsLoading] = useState<boolean>();
 46	
 47	  return (
 48	    <EmptyState variant={EmptyStateVariant.lg}>
 49	      <EmptyStateHeader
 50	        headingLevel="h4"
 51	        icon={<EmptyStateIcon icon={StorageDomainIcon} />}
 52	        titleText={<>{t('No storage checkups found')}</>}
 53	      />
 54	
 55	      <EmptyStateBody>
 56	        {t('To get started, install permissions and then run a checkup')}
 57	      </EmptyStateBody>
 58	
 59	      <EmptyStateFooter>
 60	        <EmptyStateActions>
 61	          <Button
 62	            isDisabled={!isPermitted || isLoading || namespace === ALL_NAMESPACES_SESSION_KEY}
 63	            onClick={() => navigate(createURL('form', location.pathname))}
 64	          >
 65	            {t('Run checkup')}
 66	          </Button>
 67	        </EmptyStateActions>
 68	        <EmptyStateActions>
 69	          <Button
 70	            isDisabled={
 71	              isLoading ||
 72	              loadingPermissions ||
 73	              namespace === ALL_NAMESPACES_SESSION_KEY ||
 74	              !isPermittedToInstall
 75	            }
 76	            onClick={async () => {
 77	              setIsLoading(true);
 78	              try {
 79	                await installOrRemoveCheckupsStoragePermissions(
 80	                  namespace,
 81	                  isPermitted,
 82	                  clusterRoleBinding,
 83	                );
 84	              } finally {
 85	                setIsLoading(false);
 86	              }
 87	            }}
 88	            isLoading={isLoading || loadingPermissions}
 89	            variant={isLoading ? ButtonVariant.plain : ButtonVariant.secondary}
 90	          >
 91	            {!isLoading && isPermitted ? t('Remove permissions') : t('Install permissions')}
 92	          </Button>
 93	        </EmptyStateActions>
 94	        <EmptyStateActions className="empty-state-secondary-action">
 95	          <ExternalLink
 96	            href={documentationURL.CHECKUPS}
 97	            text={t('Learn more about storage checkups')}
 98	          />
 99	        </EmptyStateActions>
100	      </EmptyStateFooter>
101	    </EmptyState>
102	  );
103	};
104	
105	export default CheckupsStorageListEmptyState;

